// Recebe o caminho do projeto
const projectPath = $input.first().json.path;

if (!projectPath) {
  throw new Error('Caminho é obrigatório!');
}

const fs = require('fs');
const path = require('path');

// Verifica se o caminho existe
if (!fs.existsSync(projectPath)) {
  throw new Error('Pasta não encontrada: ' + projectPath);
}

const stat = fs.statSync(projectPath);
if (!stat.isDirectory()) {
  throw new Error('O caminho deve ser uma pasta!');
}

const projectName = path.basename(projectPath);

// Detecta tipo de projeto
let type = 'unknown';
if (fs.existsSync(path.join(projectPath, 'package.json'))) type = 'nodejs';
else if (fs.existsSync(path.join(projectPath, 'composer.json'))) type = 'php';
else if (fs.existsSync(path.join(projectPath, 'wp-config.php'))) type = 'wordpress';
else if (fs.existsSync(path.join(projectPath, 'requirements.txt'))) type = 'python';
else if (fs.existsSync(path.join(projectPath, 'go.mod'))) type = 'go';
else if (fs.existsSync(path.join(projectPath, 'Cargo.toml'))) type = 'rust';
else if (fs.existsSync(path.join(projectPath, 'index.html'))) type = 'static';
else if (fs.existsSync(path.join(projectPath, 'main.py'))) type = 'python';

// Detecta tecnologias
const techStack = [];
try {
  if (fs.existsSync(path.join(projectPath, 'package.json'))) {
    const pkg = JSON.parse(fs.readFileSync(path.join(projectPath, 'package.json'), 'utf-8'));
    techStack.push('Node.js');
    if (pkg.dependencies?.next || pkg.devDependencies?.next) techStack.push('Next.js');
    if (pkg.dependencies?.react) techStack.push('React');
    if (pkg.dependencies?.express) techStack.push('Express');
    if (pkg.dependencies?.vue) techStack.push('Vue');
  }
  if (fs.existsSync(path.join(projectPath, 'composer.json'))) {
    techStack.push('PHP');
    const comp = JSON.parse(fs.readFileSync(path.join(projectPath, 'composer.json'), 'utf-8'));
    if (comp.require?.laravel) techStack.push('Laravel');
  }
} catch {}

return [{
  json: {
    name: projectName,
    path: projectPath,
    type: type,
    techStack: techStack,
    valid: type !== 'unknown'
  }
}];

const result = $input.first().json;

if (result.success) {
  return [{
    json: {
      message: '✅ Projeto **' + result.projectData.name + '** criado com sucesso!\n\nTipo: ' + result.projectData.type + '\nTecnologias: ' + (result.projectData.techStack?.join(', ') || 'Nenhuma')\n\nAcesse em: /projects/' + result.projectId
    }
  }];
} else {
  return [{
    json: {
      message: '❌ Erro: ' + result.error
    }
  }];
}

return [{
  json: {
    message: '❌Projeto não válido ou pasta vazia. Certifique-se de que a pasta contém um projeto com package.json, composer.json, wp-config.php, etc.'
  }
}];
